function gerarSenha(tamanho = 12) {
const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%";
let senha = "";

for (let i = 0; i < tamanho; i++) {
senha += chars.charAt(Math.floor(Math.random() * chars.length));
}

return senha;
}

return [{
service: "password-generator",
password: gerarSenha()
}];

const nomes = ["Ana","Carlos","Pedro","Marina"];
const cidades = ["São Paulo","Rio","Curitiba","Recife"];

return [{
service: "fake-user",
nome: nomes[Math.floor(Math.random()*nomes.length)],
cidade: cidades[Math.floor(Math.random()*cidades.length)],
idade: Math.floor(Math.random()*60)+18
}];

const frases = [
"Consistência vence motivação.",
"Feito é melhor que perfeito.",
"Pequenos passos todos os dias.",
"Disciplina cria liberdade."
];

return [{
service: "quote",
quote: frases[Math.floor(Math.random()*frases.length)]
}];

function validarCPF(cpf) {
cpf = cpf.replace(/[^\d]+/g,'');
if(cpf.length !== 11) return false;
return true;
}

return [{
service: "cpf-validator",
cpf: $json.cpf,
valido: validarCPF($json.cpf)
}];

const data = this.getWorkflowStaticData('global');

if (!data.visitas) {
data.visitas = 0;
}

data.visitas += 1;

return [{
service: "visit-counter",
visitas: data.visitas
}];
